"use strict";(self.webpackChunkdivine_path=self.webpackChunkdivine_path||[]).push([[588],{7619:(a,e,i)=>{i.d(e,{g:()=>l});const t=[{text:"King Dasharatha of Ayodhya, who has no sons, performs a great fire sacrifice (yagna) to ask the gods for children.",imageUrl:i.p+"static/media/ramayana_scene1.46b45a4c298bae99bf9a.png"},{text:"From the fire, a divine being emerges with a pot of sacred porridge. The king gives it to his three wives, who later give birth to four sons: Rama, Bharata, and the twins Lakshmana and Shatrughna.",imageUrl:i.p+"static/media/ramayana_scene2.d65bec5faaced1e0928e.png"},{text:"Years later, the sage Vishvamitra comes to the court and asks the teenage Prince Rama to help him by defeating demons who are disrupting his sacred rituals.",imageUrl:i.p+"static/media/ramayana_scene3.168203ed01cbd9a8c660.png"},{text:"In the forest, Rama, guided by the sage, confronts and slays the fearsome demoness Tataka with a single arrow.",imageUrl:i.p+"static/media/ramayana_scene4.9536dc23a204cf53f5b3.png"},{text:"The sage takes the princes to the kingdom of Mithila. There, Rama effortlessly lifts and breaks the divine bow of Lord Shiva, winning the hand of Princess Sita.",imageUrl:i.p+"static/media/ramayana_scene5.d38637e7446d4d762a45.png"},{text:"King Janaka joyfully gives his daughter Sita's hand to Rama. A grand procession arrives from Ayodhya, and the entire city of Mithila is decorated for the royal wedding.",imageUrl:i.p+"static/media/ramayana_scene6.7c60b90ae159a6d9c49e.png"},{text:"In a beautiful ceremony, Rama and Sita exchange flower garlands (Jaimala), signifying their acceptance of each other as husband and wife.",imageUrl:i.p+"static/media/ramayana_scene7.e82a2829fe1d99f49367.png"},{text:"After the grand wedding, Rama and his new bride, Sita, return to the joyous kingdom of Ayodhya, welcomed by all. Here ends the Bala Kanda, the book of childhood.",imageUrl:i.p+"static/media/ramayana_scene8.34b2ef52be55d70a8c0a.png"}],n=[{text:"King Dasharatha, feeling his age, decides to crown his beloved eldest son, Rama, as the heir-apparent, filling the kingdom of Ayodhya with celebration.",imageUrl:i.p+"static/media/ayodhya_scene1.94c064964bf9b0f03bec.png"},{text:"Influenced by her manipulative handmaiden Manthara, Queen Kaikeyi demands two boons from the king: that her son Bharata be crowned, and that Rama be exiled for fourteen years.",imageUrl:i.p+"static/media/ayodhya_scene2.233bf6d18479ac797080.png"},{text:"To honor his father's promise, Rama calmly accepts the harsh decree without any anger or sadness, demonstrating his unwavering commitment to dharma (duty).",imageUrl:i.p+"static/media/ayodhya_scene3.6fd949f27ed3e5fc7f01.png"},{text:"Sita and Lakshmana refuse to leave Rama's side and insist on joining him. Together, the three bid a tearful farewell to the people of Ayodhya and depart for the forest.",imageUrl:i.p+"static/media/ayodhya_scene4.8e98dd242b76b6c41f5d.png"},{text:"Consumed by grief over Rama's departure and haunted by a past curse, the heartbroken King Dasharatha passes away in his palace, unable to bear the separation.",imageUrl:i.p+"static/media/ayodhya_scene5.17efc25264a26cbfdb5a.png"},{text:"Upon returning to Ayodhya and learning of the tragedy, a furious and righteous Bharata confronts his mother Kaikeyi, rejecting the throne that was unjustly secured for him.",imageUrl:i.p+"static/media/ayodhya_scene6.074e799455a158d86ea7.png"},{text:"Bharata travels to the forest and finds Rama at Chitrakoot. He emotionally begs Rama to return and rule the kingdom, but Rama insists on fulfilling their father's vow.",imageUrl:i.p+"static/media/ayodhya_scene7.2fb80600b70f3e83b263.png"},{text:"As a compromise, Bharata takes Rama's wooden sandals (Padukas). He places them on the throne and rules the kingdom as a regent in Rama's name, never sitting on the throne himself.",imageUrl:i.p+"static/media/ayodhya_scene8.afaf6f3ec4120dbba8ba.png"},{text:"Refusing to live in the palace while Rama is in exile, Bharata establishes a simple hermitage in the village of Nandigrama, just outside Ayodhya. From here, he governs the kingdom as Rama's representative, always awaiting his brother's return. Here ends the Ayodhya Kanda.",imageUrl:i.p+"static/media/ayodhya_scene9.a76ceafd2f36aac0f21c.png"}],s=[{text:"Deep in the forest, Rama, Sita, and Lakshmana visit the hermitage of the wise Sage Atri and his devout wife, Anasuya, receiving their blessings and wisdom.",imageUrl:i.p+"static/media/aranya_scene1.4659290054c80cf5c0f1.png"},{text:"A ferocious demon named Viradha attacks them, seizing Sita. Rama and Lakshmana are forced to battle the monstrous being to rescue her.",imageUrl:i.p+"static/media/aranya_scene2.3a6c636b067a53b8fb83.png"},{text:"After settling in a new hermitage at Panchavati, their life in the forest continues peacefully. One day, a magical golden deer with silver spots appears, prancing gracefully near their cottage.",imageUrl:i.p+"static/media/aranya_scene3.5049742e293f71ce10ae.png"},{text:"Enchanted by its beauty, Sita begs Rama to capture the deer for her. Despite Lakshmana's suspicion that it's a demonic trick, Rama agrees to fulfill Sita's wish.",imageUrl:i.p+"static/media/aranya_scene4.54030c8af47fd5518d23.png"},{text:"Deep in the forest, Rama realizes the deer is a demon and shoots it. As it dies, the demon Maricha reveals his true form and cries out for help in Rama's voice.",imageUrl:i.p+"static/media/aranya_scene5.6077d41bf05c5846ec56.png"},{text:"Hearing the cry, a panicked Sita begs Lakshmana to go help his brother. Bound by duty, a reluctant Lakshmana draws a protective line around the cottage and leaves to find Rama.",imageUrl:i.p+"static/media/aranya_scene6.3bd5fd1976559054a9ac.png"},{text:"With Sita now alone, Ravana sees his chance. Disguised as a wandering holy man, he approaches the cottage and tricks Sita into crossing the protective line, then reveals his true form and carries her away in his flying chariot.",imageUrl:i.p+"static/media/aranya_scene7.568fcdb87dbbd3b929a8.png"},{text:"The heroic vulture-king Jatayu hears Sita's cries and bravely fights Ravana to stop the abduction, but is tragically struck down by the powerful demon king.",imageUrl:i.p+"static/media/aranya_scene8.24fac9b6648756c99fa5.png"},{text:"Searching frantically for Sita, Rama and Lakshmana find the grievously wounded Jatayu. With his last breath, the noble vulture king informs them that Ravana abducted Sita and headed south, before passing away peacefully.",imageUrl:i.p+"static/media/aranya_scene9.623869c2d70f3d8bae1f.png"}],r=[{text:"While searching for Sita, Rama and Lakshmana meet Hanuman, the mighty devotee and minister of Sugriva, the exiled monkey king.",imageUrl:i.p+"static/media/kishkindhaScene1.c24ed23441110d2542a8.png"},{text:"Hanuman leads them to Sugriva. Rama forms a sacred friendship pact with Sugriva, promising to help him defeat his tyrannical brother, Vali, in exchange for help finding Sita.",imageUrl:i.p+"static/media/kishkindhaScene2.ecbdadf199fc8ded8321.png"},{text:"During a fierce duel between the two brothers, Rama aids Sugriva by shooting an arrow and slaying Vali, thus making Sugriva the undisputed king of Kishkindha.",imageUrl:i.p+"static/media/kishkindhaScene3.d699109472f0bbdb86de.png"},{text:"Keeping his promise, the newly crowned King Sugriva assembles his vast army of Vanaras (monkey warriors) and sends them in all directions to search for the abducted Princess Sita.",imageUrl:i.p+"static/media/kishkindhaScene4.f6903bfb23eea5b4632a.png"},{text:"The Vanara armies search every corner of the land but fail to find any trace of Sita. The southern search party, including Hanuman and Angada, becomes despondent on a beach.",imageUrl:i.p+"static/media/kishkindhaScene5.8cd50b6063dd1ef9bac6.png"},{text:"At the edge of the ocean, the wise old bear-king Jambavan reminds Hanuman of his forgotten divine powers and his ability to fly, inspiring him to make the great leap to Lanka. Here ends the Kishkindha Kanda.",imageUrl:i.p+"static/media/kishkindhaScene6.c4380f3508d09402aff0.png"}],o=[{text:"Inspired by Jambavan, Hanuman harnesses his divine powers. He grows to a mountain-like size and takes a colossal leap from the coast of India, flying across the vast ocean towards Lanka.",imageUrl:i.p+"static/media/sundara_scene1.31e3ab201aac421f75bd.png"},{text:"During his journey, he is tested by Surasa, the mother of serpents, who swallows him whole. Hanuman cleverly shrinks to a tiny size to escape through her ear, earning her respect.",imageUrl:i.p+"static/media/sundara_scene2.26e9dc3dbe4cb78ada9e.png"},{text:"Upon reaching the island, Hanuman is confronted by Lankini, the fierce guardian demoness of the city. He defeats her with a single mighty blow, breaking her pride and entering Lanka.",imageUrl:i.p+"static/media/sundara_scene3.266caa398b8a059b90c3.png"},{text:"Before beginning his search, Hanuman marvels at the breathtaking beauty of Lanka. The golden city, with its magnificent palaces, lush gardens, and opulent architecture, seems like a celestial paradise built on earth.",imageUrl:i.p+"static/media/sundara_scene4.ec2143bce5725abe555c.png"},{text:"Adopting a tiny, cat-like form, Hanuman begins his search, moving through Lanka's magnificent palaces. He sees many Rakshasa women, but none are the virtuous Sita.",imageUrl:i.p+"static/media/sundara_scene5.457bc294c5492e85265e.png"},{text:"He enters Ravana's own chambers and sees the mighty ten-headed demon king sleeping, impressed and angered by the power of the one who stole Sita.",imageUrl:i.p+"static/media/sundara_scene6.f37dcab8ba38290b871a.png"},{text:"Hanuman feels hopeless because he can't find Sita. He worries for a moment, 'What if Sita has given up?' But he quickly shakes off the doubt, knowing her love for Rama is too strong.",imageUrl:i.p+"static/media/sundara_scene7.9056ad901b90debe299f.png"},{text:"After searching the magnificent city and even Ravana's palace, Hanuman finally finds Sita held captive in a beautiful garden, the Ashoka Vatika, looking sorrowful under a tree.",imageUrl:i.p+"static/media/sundara_scene8.aa3369054836a4542efd.png"},{text:"From his hiding place in the trees, Hanuman watches as the demon king Ravana approaches Sita, trying to intimidate and persuade her to marry him, but she steadfastly refuses.",imageUrl:i.p+"static/media/sundara_scene9.dcb6d4d182c78f5606f5.png"},{text:"When Sita is alone, Hanuman approaches her cautiously, recites the story of Rama, and gives her Rama's signet ring to prove his identity. He delivers a message of hope: Rama is coming.",imageUrl:i.p+"static/media/sundara_scene10.0303f70eb279e326a265.png"},{text:"To send a message of Rama's power, Hanuman decides to wreak havoc. He destroys the Ashoka Vatika, uprooting trees and smashing structures, which alerts Ravana's forces.",imageUrl:i.p+"static/media/sundara_scene11.f7a935269998b76a89aa.png"},{text:"Hanuman single-handedly defeats thousands of Ravana's elite Rakshasa warriors, including his powerful son, Aksha Kumara.",imageUrl:i.p+"static/media/sundara_scene12.ee679b38adacdc8c571a.png"},{text:"Finally, Ravana's mightiest son, Indrajit, uses the divine Brahmastra weapon to capture Hanuman. Respecting the weapon's power, Hanuman allows himself to be taken to Ravana's court.",imageUrl:i.p+"static/media/sundara_scene13.f432f2402980693fcb00.png"},{text:"Brought before Ravana, Hanuman introduces himself as a messenger of Rama. To show he is not inferior, he magically extends his tail, coiling it into a mighty throne to sit at the same height as the demon king.",imageUrl:i.p+"static/media/sundara_scene14.a578565c63e40be7dbea.png"},{text:"Hanuman advises Ravana to return Sita and seek forgiveness. Enraged by this audacity, Ravana roars with fury and orders his demons to wrap Hanuman's tail in cloth and set it on fire.",imageUrl:i.p+"static/media/sundara_scene15.9b8e570f5d171f585c31.png"},{text:"Using his burning tail as a weapon, Hanuman escapes his bonds. He leaps across the rooftops of Lanka, setting the entire golden city ablaze before flying back to India.",imageUrl:i.p+"static/media/sundara_scene16.7510f11771c1d9c9e3d5.png"},{text:"Hanuman returns to the waiting Vanara army and joyfully announces that he has found Sita.",imageUrl:i.p+"static/media/sundara_scene17.8d931abd95ab0c63bcc9.png"},{text:"The triumphant search party returns. Hanuman kneels before Rama and presents Sita's crest-jewel, confirming she is alive and waiting for him. Hope is restored. Here ends the Sundara Kanda.",imageUrl:i.p+"static/media/sundara_scene18.36c5d6b49a830116a7d2.png"}],h=[{text:"To cross the ocean to Lanka, Rama's Vanara army, led by the brilliant architects Nala and Nila, builds a magnificent floating bridge using rocks and trees.",imageUrl:i.p+"static/media/yuddha_scene1.401a8e1130cb45203d81.png"},{text:"With the bridge complete, the vast army of monkeys and bears, with Rama and Lakshmana at its head, marches across the sea to the shores of Lanka.",imageUrl:i.p+"static/media/yuddha_scene2.61c9a516bdf23fca34ff.png"},{text:"As a final chance for peace, Rama sends Angada, Vali's son, as an envoy to Ravana's court, demanding the peaceful return of Sita. The arrogant Ravana refuses.",imageUrl:i.p+"static/media/yuddha_scene3.bc0b5fe9ec18d2423226.png"},{text:"With all diplomatic efforts failed, the great war begins. The Vanara army clashes with the Rakshasa (demon) forces of Lanka outside the city walls in a massive, chaotic battle.",imageUrl:i.p+"static/media/yuddha_scene4.ea18b5aa57ae40b9c70f.png"},{text:"Ravana's son, Indrajit, a master of illusions and celestial weapons, grievously wounds Lakshmana with the powerful Shakti weapon, leaving him near death.",imageUrl:i.p+"static/media/yuddha_scene5.53563df23584b897275e.png"},{text:"To save Lakshmana, Hanuman flies to the Himalayas. Unable to identify the correct life-saving herb (Sanjeevani), he lifts the entire mountain and carries it back to the battlefield.",imageUrl:i.p+"static/media/yuddha_scene6.4b85735c4f3640c45de4.png"},{text:"Desperate, Ravana awakens his colossal, giant brother, Kumbhakarna, from a deep slumber. The giant warrior causes immense destruction before being slain by Rama.",imageUrl:i.p+"static/media/yuddha_scene7.2f9d9bc0bff186580238.png"},{text:"With his greatest warriors defeated, a furious Ravana finally enters the battle himself, riding his divine chariot and confronting Rama and Lakshmana directly.",imageUrl:i.p+"static/media/yuddha_scene8.916030e876eeaad645a4.png"},{text:"The final, cataclysmic duel begins between Rama and the ten-headed Ravana. The sky fills with celestial weapons as the two powerful warriors battle for the fate of the world.",imageUrl:i.p+"static/media/yuddha_scene9.8267615a725b7b8e046c.png"},{text:"After intense battle, finally, Rama unleashes the ultimate weapon, the Brahmastra. The divine arrow strikes Ravana in the heart, defeating the demon king and ending his reign of terror.",imageUrl:i.p+"static/media/yuddha_scene10.85ac24c4f996e519e8c7.png"},{text:"After Ravana falls, the gods, led by the creator Brahma, appear in the heavens. Brahma praises Rama's victory and reveals to all that he is no mere mortal, but the incarnation of Lord Vishnu, sent to earth to restore dharma.",imageUrl:i.p+"static/media/yuddha_scene11.d7f38c20a7c077e4858c.png"},{text:"After being rescued, Sita undergoes a trial by fire, the Agni Pariksha, to prove her purity to the world. She enters a blazing pyre and emerges unharmed, protected by the fire god Agni himself.",imageUrl:i.p+"static/media/yuddha_scene12.fa877aa3a0733b655de1.png"},{text:"With the 14 years of exile now complete, Rama, Sita, and Lakshmana, along with their loyal allies, triumphantly return to Ayodhya on the flying chariot, Pushpaka Vimana. Here ends the Yuddha Kanda.",imageUrl:i.p+"static/media/yuddha_scene13.2a43c63d84d9a3deb61d.png"}],d=[{text:"Upon returning to Ayodhya, Rama is crowned king in a grand coronation ceremony (Rajyabhishek). He begins a long and prosperous reign, bringing peace and happiness to his kingdom.",imageUrl:i.p+"static/media/uttara_scene1.55b895d4d0c25e5ebda5.png"},{text:"However, rumors begin to spread among the citizens of Ayodhya, questioning Queen Sita's purity after her time in Ravana's captivity.",imageUrl:i.p+"static/media/uttara_scene2.8c85b86454fdcef00d21.png"},{text:"Bound by his kingly duty (Rajadharma) to quell the public discontent, a heartbroken Rama makes the agonizing decision to send a pregnant and unknowing Sita into exile.",imageUrl:i.p+"static/media/uttara_scene3.1d8b97084230f13acd1c.png"},{text:"In the forest, Sita finds refuge in the ashram of the sage Valmiki\u2014the author of the Ramayana itself. It is here that she gives birth to her twin sons, Lava and Kusha.",imageUrl:i.p+"static/media/uttara_scene4.e8e8eb869a7711d28835.png"},{text:"Years later, during a royal ceremony, two young boys, Lava and Kusha, sing the beautiful and moving story of Rama's life, which they learned from their guru, Valmiki.",imageUrl:i.p+"static/media/uttara_scene5.826300e38f8b00d64aa4.png"},{text:"As they recite the tale of Sita's exile, Rama is overcome with emotion and recognizes the two boys as his own sons. He asks Valmiki to bring Sita to the court to prove her purity once more.",imageUrl:i.p+"static/media/uttara_scene6.f19ba3551584626d5bba.png"},{text:"At the royal court, instead of undergoing another trial, Sita declares her unwavering purity and asks her mother, Bhumi Devi (Mother Earth), to receive her. The earth opens up, and Sita returns to her mother's embrace, concluding her earthly journey.",imageUrl:i.p+"static/media/uttara_scene7.68aa93228f0f126fb40a.png"},{text:"Rama rules Ayodhya for many prosperous years in a golden age known as Rama Rajya. He eventually passes the kingdom to his sons, Lava and Kusha.",imageUrl:i.p+"static/media/uttara_scene8.8495a7945ae4dabb2a18.png"},{text:"Rama returns to his celestial form as Vishnu. Here concludes the sacred epic, a timeless story of dharma, devotion, and the victory of good over evil.",imageUrl:i.p+"static/media/uttara_scene9.6c806df5dc6a95db3f5e.png"}],l=[{id:1,title:"Ramayana",type:"epic",summary:"An ancient epic which follows the journey of Prince Rama to rescue his wife Sita from the demon king Ravana.",imageUrl:i.p+"static/media/ramayana.68d5895a8f4e4a93d9d7.png",introduction:"The Ramayana, attributed to the sage Valmiki, is a foundational epic of Hindu literature. It narrates the life and trials of Rama, the seventh avatar of Vishnu. The story is traditionally divided into seven books, or Kandas, each detailing a different phase of his remarkable journey.",kandas:[{title:"Bala Kanda (Book of Childhood)",summary:"The birth and early life of Rama and his brothers, their education, and Rama's marriage to Sita.",scenes:t},{title:"Ayodhya Kanda (Book of Ayodhya)",summary:"The preparations for Rama's coronation and his sudden, heartbreaking exile to the forest for 14 years.",scenes:n},{title:"Aranya Kanda (Book of the Forest)",summary:"Life in the forest and the abduction of Sita by the demon king Ravana.",scenes:s},{title:"Kishkindha Kanda (Book of the Monkey Kingdom)",summary:"Rama's alliance with the monkey king Sugriva and the launch of the search for Sita.",scenes:r},{title:"Sundara Kanda (Book of Beauty)",summary:"Hanuman's heroic journey to Lanka, his discovery of Sita, and his report back to Rama.",scenes:o},{title:"Yuddha Kanda (Book of War)",summary:"The epic battle between Rama's army and Ravana's forces, culminating in Ravana's defeat.",scenes:h},{title:"Uttara Kanda (Epilogue)",summary:"The final years of Rama and Sita, and the conclusion of their story.",scenes:d}]},{id:2,title:"Mahabharata",type:"summary",summary:"One of the two major Sanskrit epics...",imageUrl:i.p+"static/media/mahabharata.10dbf964c648c79f9b01.png",fullStory:"The Mahabharata is the longest epic poem ever written...",storyScenes:[]},{id:3,title:"Bhagavad Gita",type:"scripture",summary:"The divine dialogue between Lord Krishna and Arjuna on the battlefield of Kurukshetra, covering philosophy, devotion, and the path to enlightenment.",imageUrl:"/assets/images/bhagavad_gita.png",introduction:"The Bhagavad Gita, often referred to as the Gita, is a 700-verse Hindu scripture that is part of the epic Mahabharata. It presents a synthesis of Hindu ideas about dharma, theistic bhakti, and the yogic ideals of moksha. The text is a dialogue between Prince Arjuna and the god Krishna, who serves as his charioteer.",hasAudio:!0,hasIllustrations:!0,chapters:[{number:1,title:"Arjuna Vishada Yoga (The Yoga of Arjuna's Dejection)",verses:47,summary:"Arjuna sees his friends and relatives on the opposing side and is overcome with grief and moral dilemma about fighting them.",keyTeachings:["Setting the stage for the discourse","Arjuna's moral crisis","The nature of duty and righteousness"],audioUrl:null,illustration:null,sampleVerses:[{number:1,sanskrit:"\u0927\u0943\u0924\u0930\u093e\u0937\u094d\u091f\u094d\u0930 \u0909\u0935\u093e\u091a | \u0927\u0930\u094d\u092e\u0915\u094d\u0937\u0947\u0924\u094d\u0930\u0947 \u0915\u0941\u0930\u0941\u0915\u094d\u0937\u0947\u0924\u094d\u0930\u0947 \u0938\u092e\u0935\u0947\u0924\u093e \u092f\u0941\u092f\u0941\u0924\u094d\u0938\u0935\u0903 |",transliteration:"dh\u1e5btar\u0101\u1e63\u1e6dra uv\u0101ca | dharma-k\u1e63etre kuru-k\u1e63etre samavet\u0101 yuyutsava\u1e25",translation:"Dhritarashtra said: O Sanjaya, what did my sons and the sons of Pandu do when they assembled on the sacred field of Kurukshetra, eager for battle?"}]},{number:2,title:"Sankhya Yoga (The Yoga of Knowledge)",verses:72,summary:"Krishna begins his teachings, explaining the eternal nature of the soul and introducing the concept of Karma Yoga.",keyTeachings:["The immortality of the soul","The path of selfless action (Karma Yoga)","Equanimity in success and failure","The nature of the self-realized person"],audioUrl:null,illustration:null,sampleVerses:[{number:47,sanskrit:"\u0915\u0930\u094d\u092e\u0923\u094d\u092f\u0947\u0935\u093e\u0927\u093f\u0915\u093e\u0930\u0938\u094d\u0924\u0947 \u092e\u093e \u092b\u0932\u0947\u0937\u0941 \u0915\u0926\u093e\u091a\u0928 |",transliteration:"karma\u1e47y-ev\u0101dhik\u0101ras te m\u0101 phale\u1e63u kad\u0101cana",translation:"You have a right to perform your prescribed duty, but you are not entitled to the fruits of action."}]},{number:3,title:"Karma Yoga (The Yoga of Action)",verses:43,summary:"Krishna elaborates on Karma Yoga, explaining the importance of performing one's duty without attachment to results.",keyTeachings:["The importance of action","Selfless service","Transcending desire and attachment","The role of sacrifice (yajna)"],audioUrl:null,illustration:null},{number:4,title:"Jnana Karma Sanyasa Yoga (The Yoga of Knowledge and Renunciation)",verses:42,summary:"Krishna reveals his divine nature, the purpose of his incarnations, and the relationship between knowledge and action.",keyTeachings:["Divine incarnation (Avatar)","The ancient yoga tradition","Knowledge through sacrifice","The nature of action and inaction"],audioUrl:null,illustration:null},{number:5,title:"Karma Sanyasa Yoga (The Yoga of Renunciation of Action)",verses:29,summary:"Krishna explains that both the path of renunciation and the path of selfless action lead to liberation.",keyTeachings:["Unity of knowledge and action","True renunciation","Inner peace through detachment","Seeing the divine in all beings"],audioUrl:null,illustration:null},{number:6,title:"Atma Samyama Yoga (The Yoga of Self-Mastery)",verses:47,summary:"Krishna describes the practice of meditation and the discipline required to control the mind.",keyTeachings:["The practice of meditation (dhyana)","Controlling the mind","The characteristics of a true yogi","Gradual progress on the spiritual path"],audioUrl:null,illustration:null},{number:7,title:"Jnana Vijnana Yoga (The Yoga of Knowledge and Wisdom)",verses:30,summary:"Krishna explains his divine nature and the different paths devotees take to reach him.",keyTeachings:["Knowledge of the Absolute Truth","Material and spiritual nature","Different types of devotees","The rare soul who truly knows Krishna"],audioUrl:null,illustration:null},{number:8,title:"Aksara Brahma Yoga (The Yoga of the Imperishable Absolute)",verses:28,summary:"Krishna explains the concepts of the imperishable Brahman, karma, and how to remember him at the time of death.",keyTeachings:["The nature of Brahman","Remembering God at death","The path of light and darkness after death","Unwavering devotion"],audioUrl:null,illustration:null},{number:9,title:"Raja Vidya Raja Guhya Yoga (The Yoga of Royal Knowledge and Royal Secret)",verses:34,summary:"Krishna reveals the most confidential knowledge about devotion and how all creation emanates from and returns to him.",keyTeachings:["The supreme secret","Divine manifestation in creation","Pure devotion (bhakti)","God's equal love for all"],audioUrl:null,illustration:null},{number:10,title:"Vibhuti Yoga (The Yoga of Divine Glories)",verses:42,summary:"Krishna describes his divine manifestations and glories that can be perceived in the world.",keyTeachings:["Divine manifestations in creation","The glory of God in all things","How to see the divine everywhere","Krishna as the source of all"],audioUrl:null,illustration:null},{number:11,title:"Visvarupa Darsana Yoga (The Yoga of the Vision of the Universal Form)",verses:55,summary:"Arjuna requests to see Krishna's universal form. Krishna grants him divine vision to behold his cosmic manifestation.",keyTeachings:["The universal form of God","Divine vision granted to Arjuna","The awesome power of the Supreme","Return to the personal form"],audioUrl:null,illustration:null,isIconic:!0},{number:12,title:"Bhakti Yoga (The Yoga of Devotion)",verses:20,summary:"Krishna explains the path of devotion and the qualities of his devotees.",keyTeachings:["The superiority of bhakti (devotion)","Qualities of a true devotee","Personal vs. impersonal worship","The path most dear to Krishna"],audioUrl:null,illustration:null},{number:13,title:"Ksetra Ksetrajna Vibhaga Yoga (The Yoga of Distinction between Field and Knower)",verses:35,summary:"Krishna explains the difference between the body (field) and the soul (knower of the field).",keyTeachings:["The body and the knower of the body","Material nature and consciousness","Knowledge and the object of knowledge","The Supreme Soul in all beings"],audioUrl:null,illustration:null},{number:14,title:"Gunatraya Vibhaga Yoga (The Yoga of Division of Three Gunas)",verses:27,summary:"Krishna describes the three modes of material nature (gunas) and how to transcend them.",keyTeachings:["The three gunas: sattva, rajas, tamas","How the gunas bind the soul","Transcending the gunas","Symptoms of one who has transcended"],audioUrl:null,illustration:null},{number:15,title:"Purusottama Yoga (The Yoga of the Supreme Person)",verses:20,summary:"Krishna describes the imperishable tree of material existence and reveals himself as the Supreme Person.",keyTeachings:["The cosmic tree of material existence","The perishable and imperishable","The Supreme Person (Purushottama)","Knowledge that leads to liberation"],audioUrl:null,illustration:null},{number:16,title:"Daivasura Sampad Vibhaga Yoga (The Yoga of Divine and Demoniac Natures)",verses:24,summary:"Krishna contrasts divine and demoniac qualities, explaining which lead to liberation and which to bondage.",keyTeachings:["Divine qualities (daivi sampad)","Demoniac qualities (asuri sampad)","The fate of the demoniac","The importance of scripture"],audioUrl:null,illustration:null},{number:17,title:"Sraddhatraya Vibhaga Yoga (The Yoga of Division of Three Kinds of Faith)",verses:28,summary:"Krishna explains how the three gunas influence faith, worship, food, sacrifice, austerity, and charity.",keyTeachings:["Three types of faith","Worship according to one's nature","Sattvic, rajasic, and tamasic foods","Charity, austerity, and sacrifice in three modes"],audioUrl:null,illustration:null},{number:18,title:"Moksa Sanyasa Yoga (The Yoga of Liberation through Renunciation)",verses:78,summary:"The final chapter synthesizes all teachings, emphasizing complete surrender to Krishna as the ultimate path to liberation.",keyTeachings:["True renunciation vs. abandonment","Types of knowledge, action, and doer","The five factors of action","Complete surrender to God","The ultimate instruction: abandon all dharmas and surrender"],audioUrl:null,illustration:null,isConclusion:!0}]},{id:4,title:"Vishnu Purana",type:"purana",summary:"One of the eighteen Mahapuranas, this sacred text glorifies Lord Vishnu and describes the creation, maintenance, and dissolution of the universe.",imageUrl:"/assets/images/vishnu_purana.png",introduction:"The Vishnu Purana is one of the eighteen Mahapuranas and is considered one of the most important Puranas. It describes the creation of the universe, the genealogy of gods and sages, the avatars of Vishnu, and provides guidelines for living a righteous life. It consists of six books (amshas) with approximately 23,000 verses.",hasAudio:!0,hasIllustrations:!0,books:[{number:1,title:"Book One: Creation",summary:"The creation of the universe, the genealogy of gods, sages, and the first Manu. Describes the cosmic cycles and the nature of time.",chapters:22,keyTopics:["Creation of the universe by Brahma","The story of Dhruva's devotion","Genealogy of gods and sages","The story of Prahlada and Hiranyakashipu","Cosmic time cycles (yugas)"],audioUrl:null,illustration:null,stories:[{title:"Dhruva's Devotion",summary:"The story of young prince Dhruva who through intense devotion to Vishnu attained the Pole Star position.",hasIllustration:!0,illustrationUrl:null},{title:"Prahlada and Hiranyakashipu",summary:"The demon king Hiranyakashipu's conflict with his devotee son Prahlada, leading to Vishnu's Narasimha avatar.",hasIllustration:!0,illustrationUrl:null}]},{number:2,title:"Book Two: The Earth and Its Divisions",summary:"Describes the geography of Earth, its divisions, mountains, rivers, and the organization of society.",chapters:16,keyTopics:["Geography of Jambudvipa (ancient India)","The seven continents and seven oceans","Sacred rivers and mountains","The organization of varnas (social classes)","Duties of different life stages (ashramas)"],audioUrl:null,illustration:null},{number:3,title:"Book Three: Divisions of Time and Social Duties",summary:"Explains the divisions of time, the duties of the four varnas and four ashramas, and rules for daily conduct.",chapters:18,keyTopics:["Measurement of time from atoms to yugas","Duties of Brahmanas, Kshatriyas, Vaishyas, and Shudras","The four ashramas: student, householder, hermit, renunciate","Rules for daily worship and rituals","The path to liberation"],audioUrl:null,illustration:null},{number:4,title:"Book Four: Royal Dynasties",summary:"Genealogies of kings from the Solar and Lunar dynasties, including the story of Krishna and the Pandavas.",chapters:24,keyTopics:["Solar dynasty (Suryavansha) - Rama's lineage","Lunar dynasty (Chandravansha) - Krishna's lineage","The story of Krishna's birth and childhood","Krishna's role in the Mahabharata","Future kings and the Kali Yuga"],audioUrl:null,illustration:null,stories:[{title:"Krishna's Birth and Childhood",summary:"The miraculous birth of Krishna in prison, his childhood in Gokul, and his divine pastimes.",hasIllustration:!0,illustrationUrl:null}]},{number:5,title:"Book Five: Krishna's Life",summary:"Detailed account of Krishna's life from his youth in Vrindavan to his role in establishing dharma.",chapters:38,keyTopics:["Krishna's pastimes in Vrindavan","Krishna and the Gopis","Killing of various demons","Krishna in Mathura and Dwaraka","Krishna's teachings and divine play"],audioUrl:null,illustration:null,stories:[{title:"Krishna and the Gopis",summary:"The divine love between Krishna and the Gopis, exemplifying the highest devotion.",hasIllustration:!0,illustrationUrl:null},{title:"Lifting Govardhan Hill",summary:"Krishna lifts the Govardhan mountain to protect the villagers from Indra's wrath.",hasIllustration:!0,illustrationUrl:null}]},{number:6,title:"Book Six: Dissolution and Liberation",summary:"Describes the end of Krishna's earthly avatar, the Kali Yuga, and the path to moksha (liberation).",chapters:8,keyTopics:["Krishna's departure from Earth","The beginning of Kali Yuga","Signs of Kali Yuga","The path to liberation through devotion","The ultimate dissolution of the universe"],audioUrl:null,illustration:null}]},{id:5,title:"Shiva Purana",type:"purana",summary:"One of the eighteen Mahapuranas, dedicated to Lord Shiva, describing his glory, forms, sacred places, and stories of devotees.",imageUrl:"/assets/images/shiva_purana.png",introduction:"The Shiva Purana is one of the eighteen Mahapuranas and is dedicated to Lord Shiva. It glorifies Shiva as the supreme being, describes his various forms and manifestations, narrates stories of his devotees, and provides guidelines for worship and spiritual practices. It contains approximately 24,000 verses organized into seven samhitas (sections).",hasAudio:!0,hasIllustrations:!0,samhitas:[{number:1,title:"Vidyeshvara Samhita",summary:"Introduces the glory of Shiva, the creation of the universe, and fundamental Shaivite philosophy.",chapters:25,keyTopics:["Glory and supremacy of Shiva","Creation through Shiva's will","The nature of Shiva's forms","The importance of Shiva worship","The power of the sacred syllable 'Om Namah Shivaya'"],audioUrl:null,illustration:null},{number:2,title:"Rudra Samhita",summary:"The largest section describing Shiva's various manifestations, his marriage to Sati and Parvati, and stories of his devotees.",chapters:67,keyTopics:["Birth of Rudra (Shiva)","The story of Daksha's sacrifice and Sati's self-immolation","Shiva's marriage to Parvati","Birth of Kartikeya and Ganesha","Various forms and avatars of Shiva","Stories of devoted followers"],audioUrl:null,illustration:null,stories:[{title:"Daksha's Sacrifice and Sati's Sacrifice",summary:"Sati attends her father Daksha's sacrifice despite Shiva not being invited. Unable to bear the insult to Shiva, she immolates herself.",hasIllustration:!0,illustrationUrl:null,keyMessage:"Devotion to one's chosen deity above all else"},{title:"Shiva's Marriage to Parvati",summary:"After Sati's death, she is reborn as Parvati and performs severe penance to win Shiva as her husband.",hasIllustration:!0,illustrationUrl:null,keyMessage:"The power of devotion and determination"},{title:"Birth of Ganesha",summary:"Parvati creates Ganesha from sandalwood paste. Shiva unknowingly beheads him and later restores him with an elephant's head.",hasIllustration:!0,illustrationUrl:null,keyMessage:"Obedience and the blessings of misfortune"}]},{number:3,title:"Shatrudra Samhita",summary:"Describes the hundred forms of Rudra and their significance in creation and destruction.",chapters:42,keyTopics:["The hundred Rudras and their manifestations","The cosmic dance of Shiva (Tandava)","Shiva as the destroyer and regenerator","The significance of Shiva's third eye","Shiva's role in the cosmic cycles"],audioUrl:null,illustration:null,stories:[{title:"The Cosmic Dance (Tandava)",summary:"Shiva performs the Tandava, the cosmic dance of creation, preservation, and destruction.",hasIllustration:!0,illustrationUrl:null,keyMessage:"The rhythm of the universe"}]},{number:4,title:"Koti Rudra Samhita",summary:"Elaborates on the countless forms of Shiva and methods of worshipping him.",chapters:43,keyTopics:["Infinite forms of Shiva","Methods of Shiva worship","The significance of the Shiva Linga","Sacred mantras and their powers","Rituals for different occasions"],audioUrl:null,illustration:null},{number:5,title:"Uma Samhita",summary:"Contains dialogues between Shiva and Parvati (Uma) on various philosophical and spiritual topics.",chapters:51,keyTopics:["Philosophical dialogues between Shiva and Parvati","The nature of reality and illusion (Maya)","The path to liberation","The relationship between the devotee and God","Yoga and meditation practices"],audioUrl:null,illustration:null},{number:6,title:"Kailasa Samhita",summary:"Describes Mount Kailash, Shiva's abode, and the glory of his sacred places.",chapters:23,keyTopics:["Mount Kailash - Shiva's abode","The twelve Jyotirlingas","Sacred Shiva temples","Holy rivers associated with Shiva","Pilgrimage to Shiva's sacred places"],audioUrl:null,illustration:null,sacredPlaces:[{name:"Somnath",location:"Gujarat",significance:"First Jyotirlinga"},{name:"Mallikarjuna",location:"Andhra Pradesh",significance:"Second Jyotirlinga"},{name:"Mahakaleshwar",location:"Ujjain, Madhya Pradesh",significance:"Third Jyotirlinga"},{name:"Omkareshwar",location:"Madhya Pradesh",significance:"Fourth Jyotirlinga"},{name:"Kedarnath",location:"Uttarakhand",significance:"Fifth Jyotirlinga"},{name:"Bhimashankar",location:"Maharashtra",significance:"Sixth Jyotirlinga"},{name:"Kashi Vishwanath",location:"Varanasi, Uttar Pradesh",significance:"Seventh Jyotirlinga"},{name:"Trimbakeshwar",location:"Maharashtra",significance:"Eighth Jyotirlinga"},{name:"Vaidyanath",location:"Jharkhand",significance:"Ninth Jyotirlinga"},{name:"Nageshwar",location:"Gujarat",significance:"Tenth Jyotirlinga"},{name:"Rameshwaram",location:"Tamil Nadu",significance:"Eleventh Jyotirlinga"},{name:"Grishneshwar",location:"Maharashtra",significance:"Twelfth Jyotirlinga"}]},{number:7,title:"Vayaviya Samhita",summary:"Contains teachings given by Vayu (wind god) about Shiva worship and spiritual practices.",chapters:30,keyTopics:["Advanced spiritual practices","Esoteric knowledge of Shiva","The power of devotion (bhakti)","Liberation through Shiva's grace","Stories of great Shiva devotees"],audioUrl:null,illustration:null,stories:[{title:"Markandeya's Devotion",summary:"Young Markandeya, destined to die at sixteen, defeats death through his unwavering devotion to Shiva.",hasIllustration:!0,illustrationUrl:null,keyMessage:"Devotion can conquer even death"}]}]}]}}]);